SELECT p.*, t.transaction_no, u1.real_name as finance_name, u2.real_name as audit_name FROM tb_payment p LEFT JOIN tb_transaction t ON p.transaction_id = t.id LEFT JOIN sys_user u1 ON p.finance_id = u1.id LEFT JOIN sys_user u2 ON p.audit_user_id = u2.id
p.is_deleted = 0
AND p.transaction_id = #{query.transactionId}
AND t.transaction_no LIKE CONCAT('%', #{query.transactionNo}, '%')
AND p.payment_type = #{query.paymentType}
AND p.payment_status = #{query.paymentStatus}
ORDER BY p.create_time DESC

